export function mergeIntervals(intervals: [number, number][]): [number, number][] {
	if (intervals.length === 0) {
		return [];
	}

	// Sort intervals based on the start time
	intervals.sort((a, b) => a[0] - b[0]);

	const merged: [number, number][] = [];

	// Initialize the first merged interval
	let currentStart = intervals[0][0];
	let currentEnd = intervals[0][1];

	for (let i = 1; i < intervals.length; i++) {
		const nextStart = intervals[i][0];
		const nextEnd = intervals[i][1];

		// Check for overlap
		if (nextStart <= currentEnd) {
			// Merge: update the end time
			currentEnd = Math.max(currentEnd, nextEnd);
		} else {
			// No overlap: push the current merged interval and start a new one
			merged.push([currentStart, currentEnd]);
			currentStart = nextStart;
			currentEnd = nextEnd;
		}
	}

	// Push the last processed interval
	merged.push([currentStart, currentEnd]);

	return merged;
}

