export function mergeSortLinkedList(head: {value: number; next: any} | null): {value: number; next: any} | null {
	if (!head || !head.next) {
		return head;
	}

	// 1. Split the list into two halves
	let slow: {value: number; next: any} | null = head;
	let fast: {value: number; next: any} | null = head.next;

	// Find the middle point using slow/fast pointers
	// slow will point to the end of the first half
	while (fast && fast.next) {
		slow = slow!.next;
		fast = fast.next.next;
	}

	// slow is now the last node of the first half.
	let head1 = head;
	let head2 = slow!.next;
	slow!.next = null; // Break the link

	// 2. Recursively sort the two halves
	let sorted1 = mergeSortLinkedList(head1);
	let sorted2 = mergeSortLinkedList(head2);

	// 3. Merge the sorted halves
	return merge(sorted1, sorted2);
}

function merge(a: {value: number; next: any} | null, b: {value: number; next: any} | null): {value: number; next: any} | null {
	// Create a dummy head for the merged list
	const dummyHead: {value: number; next: any} = {value: 0, next: null};
	let current = dummyHead;

	// Merge elements
	while (a && b) {
		if (a.value <= b.value) {
			current.next = a;
			a = a.next;
		} else {
			current.next = b;
			b = b.next;
		}
		current = current.next;
	}

	// Append remaining elements
	if (a) {
		current.next = a;
	} else if (b) {
		current.next = b;
	}

	return dummyHead.next;
}

