export function minStack(operations: readonly (readonly ['push' | 'pop' | 'top' | 'getMin', number?])[]): (number | null)[] {
	const stack: number[] = [];
	const min_tracker: number[] = [];
	const results: (number | null)[] = [];

	for (const op of operations) {
		const type = op[0];
		const value = op[1];

		switch (type) {
			case 'push':
				stack.push(value!);
				if (min_tracker.length === 0) {
					min_tracker.push(value!);
				} else {
					const currentMin = min_tracker[min_tracker.length - 1];
					min_tracker.push(Math.min(value!, currentMin));
				}
				results.push(undefined); // Push operation doesn't return a value

				break;

			case 'pop':
				if (stack.length === 0) {
					// Handle error or undefined behavior if popping from empty stack
					results.push(null);
					break;
				}
				const poppedValue = stack.pop()!;

				// Pop from min_tracker as well
				min_tracker.pop();

				results.push(poppedValue);
				break;

			case 'top':
				if (stack.length === 0) {
					results.push(null);
				} else {
					results.push(stack[stack.length - 1]);
				}
				break;

			case 'getMin':
				if (min_tracker.length === 0) {
					results.push(null);
				} else {
					results.push(min_tracker[min_tracker.length - 1]);
				}
				break;
		}
	}

	return results;
}

