export function productOfArrayExceptSelf(values: number[]): number[] {
	const n = values.length;
	const result = new Array(n).fill(1);

	// Calculate prefix products (products of all elements to the left of i)
	let prefixProduct = 1;
	for (let i = 0; i < n; i++) {
		result[i] = prefixProduct;
		prefixProduct *= values[i];
	}

	// Calculate suffix products (products of all elements to the right of i)
	let suffixProduct = 1;
	for (let i = n - 1; i >= 0; i--) {
		result[i] *= suffixProduct;
		suffixProduct *= values[i];
	}

	return result;
}

